-- Migration 013: Encyclopedia upgrades
-- Adds pro_tips to exercises, secondary_muscles + seat_adjustment to equipment
-- Seeds exercise GIFs from open-source ExerciseDB API

ALTER TABLE public.exercises
  ADD COLUMN IF NOT EXISTS pro_tips TEXT[] NOT NULL DEFAULT '{}';

ALTER TABLE public.equipment
  ADD COLUMN IF NOT EXISTS secondary_muscles TEXT[] NOT NULL DEFAULT '{}',
  ADD COLUMN IF NOT EXISTS seat_adjustment TEXT[] NOT NULL DEFAULT '{}';

